$ErrorActionPreference = "Stop"

$project = "C:\Users\arauj\grafica-flash"

if (!(Test-Path -LiteralPath $project)) {
  Write-Host "Projeto nao encontrado em $project" -ForegroundColor Red
  exit 1
}

Set-Location -LiteralPath $project
$utf8NoBom = New-Object System.Text.UTF8Encoding($false)

function Write-Base64File($relativePath, $base64Content) {
  $target = Join-Path $project $relativePath
  $directory = Split-Path $target -Parent
  New-Item -ItemType Directory -Force -Path $directory | Out-Null

  if (Test-Path -LiteralPath $target) {
    $backup = $target + ".backup-estabilizacao-modulos-" + (Get-Date -Format "yyyyMMddHHmmss")
    Copy-Item -LiteralPath $target -Destination $backup -Force
    Write-Host "Backup criado: $backup" -ForegroundColor DarkYellow
  }

  $bytes = [System.Convert]::FromBase64String($base64Content.Trim())
  $content = [System.Text.Encoding]::UTF8.GetString($bytes)
  [System.IO.File]::WriteAllText($target, $content, $utf8NoBom)
  Write-Host "Atualizado: $relativePath" -ForegroundColor Green
}

Write-Base64File "lib\panel-modules.ts" @"

"@

Write-Base64File "lib\plan-limits.ts" @"

"@

Write-Base64File "app\painel\modulos\[module]\page.tsx" @"

"@

# Limpa cache do Next/Turbopack para parar de usar arquivo antigo.
Remove-Item -Recurse -Force ".next" -ErrorAction SilentlyContinue
Remove-Item -Recurse -Force ".turbo" -ErrorAction SilentlyContinue

Write-Host ""
Write-Host "Estabilização aplicada." -ForegroundColor Green
Write-Host "Agora rode: npm run build" -ForegroundColor Yellow
